SELECT

FROM gen_table_derive_config a
WHERE a.del_flag = #{DEL_FLAG_NORMAL}

    AND a.gen_table_id = #{genTableId}

ORDER BY a.update_date DESC, a.create_date DESC

mapper.update:
UPDATE gen_table_derive_config SET
    last_run_time = #{lastRunTime},
    last_run_status = #{lastRunStatus},
    last_run_message = #{lastRunMessage},
    update_date = #{updateDate}
WHERE id = #{id}

UPDATE gen_table_derive_config SET
    del_flag = #{DEL_FLAG_DELETE}
WHERE id = #{id}

UPDATE gen_table_derive_config SET
    del_flag = '1'
WHERE gen_table_id = #{genTableId}
